  1	import * as React from "react";
  2	import {
  3	  Alert,
  4	  Button,
  5	  AlertActionCloseButton,
  6	  Form,
  7	  Flex,
  8	  FlexItem,
  9	} from "@patternfly/react-core";
 10	import { useField, useFormikContext, FormikValues } from "formik";
 11	
 12	import { EditorType } from "data/types";
 13	import { useEditorType } from "../synced-editor/useEditorType";
 14	import RadioGroupField from "./RadioGroupField";
 15	import { load, dump } from "js-yaml";
 16	import { useNodeHealthCheckTranslation } from "localization/useNodeHealthCheckTranslation";
 17	import { LoadingBox } from "copiedFromConsole/utils/status-box";
 18	import { get, isEmpty } from "lodash-es";
 19	
 20	type FormErrorCallback<ReturnValue = Record<string, unknown>> =
 21	  () => ReturnValue;
 22	type WithOrWithoutPromise<Type> = Promise<Type> | Type;
 23	export type SanitizeToForm<
 24	  YAMLStruct = Record<string, unknown>,
 25	  FormOutput = Record<string, unknown>
 26	> = (
 27	  preFormData: YAMLStruct
 28	) => WithOrWithoutPromise<FormOutput | FormErrorCallback<FormOutput>>;
 29	export type SanitizeToYAML = (preFormData: string) => string;
 30	
 31	type EditorContext<SanitizeTo> = {
 32	  name: string;
 33	  editor: React.ReactNode;
 34	  isDisabled?: boolean;
 35	  sanitizeTo?: SanitizeTo;
 36	  label?: string;
 37	};
 38	
 39	type SyncedEditorFieldProps = {
 40	  name: string;
 41	  formContext: EditorContext<SanitizeToForm>;
 42	  yamlContext: EditorContext<SanitizeToYAML>;
 43	  lastViewUserSettingKey: string;
 44	  prune?: (data: unknown) => unknown;
 45	  noMargin?: boolean;
 46	};
 47	
 48	const SyncedEditorField: React.FC<SyncedEditorFieldProps> = ({
 49	  name,
 50	  formContext,
 51	  yamlContext,
 52	  prune,
 53	  noMargin = false,
 54	  lastViewUserSettingKey,
 55	}) => {
 56	  const { t } = useNodeHealthCheckTranslation();
 57	  const [field] = useField(name);
 58	
 59	  const { values, setFieldValue } = useFormikContext<FormikValues>();
 60	
 61	  const formData = get(values, formContext.name);
 62	  const yamlData: string = get(values, yamlContext.name);
 63	
 64	  const [yamlWarning, setYAMLWarning] = React.useState<boolean>(false);
 65	  const [sanitizeToCallback, setSanitizeToCallback] =
 66	    React.useState<FormErrorCallback>(undefined);
 67	  const [disabledFormAlert, setDisabledFormAlert] = React.useState<boolean>(
 68	    formContext.isDisabled
 69	  );
 70	
 71	  const isEditorTypeEnabled = (type: EditorType): boolean =>
 72	    !(type === EditorType.Form
 73	      ? formContext?.isDisabled
 74	      : yamlContext?.isDisabled);
 75	
 76	  const [editorType, setEditorType, resourceLoaded] = useEditorType(
 77	    lastViewUserSettingKey,
 78	    field.value as EditorType,
 79	    isEditorTypeEnabled
 80	  );
 81	
 82	  const loaded = resourceLoaded && field.value === editorType;
 83	
 84	  const changeEditorType = (newType: EditorType) => {
 85	    setEditorType(newType);
 86	    setFieldValue(name, newType);
 87	  };
 88	
 89	  const handleToggleToForm = async () => {
 90	    // Convert from YAML
 91	    let content = {};
 92	    try {
 93	      content = load(yamlData);
 94	    } catch (err) {
 95	      content = {};
 96	    }
 97	
 98	    // Sanitize the YAML structure if possible
 99	    if (!isEmpty(content)) {
100	      if (formContext.sanitizeTo) {
101	        try {
102	          content = await formContext.sanitizeTo(content);
103	        } catch (e) {
104	          // Failed to sanitize, discard invalid data
105	          content = null;
106	          console.error(e);
107	        }
108	      }
109	
110	      // Handle sanitized result
111	      if (typeof content === "object" && !isEmpty(content)) {
112	        setFieldValue(formContext.name, content);
113	        changeEditorType(EditorType.Form);
114	        return;
115	      }
116	      if (typeof content === "function") {
117	        setSanitizeToCallback(() => content);
118	      }
119	    }
120	
121	    setYAMLWarning(true);
122	  };
123	
124	  const handleToggleToYAML = () => {
125	    const newYAML = dump(prune?.(formData) ?? formData, {
126	      skipInvalid: true,
127	    });
128	    setFieldValue(
129	      yamlContext.name,
130	      yamlContext.sanitizeTo ? yamlContext.sanitizeTo(newYAML) : newYAML
131	    );
132	    changeEditorType(EditorType.YAML);
133	  };
134	
135	  const onClickYAMLWarningConfirm = async () => {
136	    setYAMLWarning(false);
137	    if (sanitizeToCallback) {
138	      setFieldValue(formContext.name, sanitizeToCallback());
139	    }
140	    changeEditorType(EditorType.Form);
141	  };
142	
143	  const onClickYAMLWarningCancel = () => {
144	    setYAMLWarning(false);
145	  };
146	
147	  const onChangeType = (newType: EditorType) => {
148	    switch (newType) {
149	      case EditorType.YAML:
150	        handleToggleToYAML();
151	        break;
152	      case EditorType.Form:
153	        handleToggleToForm();
154	        break;
155	      default:
156	        break;
157	    }
158	  };
159	
160	  React.useEffect(() => {
161	    setDisabledFormAlert(formContext.isDisabled);
162	    if (resourceLoaded && field.value !== editorType) {
163	      setFieldValue(name, editorType);
164	    }
165	  }, [
166	    editorType,
167	    field.value,
168	    formContext.isDisabled,
169	    name,
170	    resourceLoaded,
171	    setFieldValue,
172	  ]);
173	
174	  return loaded ? (
175	    <Flex
176	      direction={{ default: "column" }}
177	      spaceItems={{ default: "spaceItemsMd" }}
178	      style={{ height: "100%" }}
179	    >
180	      <FlexItem>
181	        <Form>
182	          <RadioGroupField
183	            label={t("Configure via:")}
184	            name={name}
185	            className="nhc-form-synced-editor-field"
186	            options={[
187	              {
188	                label: formContext.label || t("Form view"),
189	                value: EditorType.Form,
190	                isDisabled: formContext.isDisabled,
191	              },
192	              {
193	                label: yamlContext.label || t("YAML view"),
194	                value: EditorType.YAML,
195	                isDisabled: yamlContext.isDisabled,
196	              },
197	            ]}
198	            onChange={(val: string) => onChangeType(val as EditorType)}
199	            isInline
200	          />
201	        </Form>
202	      </FlexItem>
203	
204	      {yamlWarning && (
205	        <FlexItem>
206	          <Alert
207	            variant="danger"
208	            isInline
209	            title={t("Invalid YAML cannot be persisted")}
210	          >
211	            <p>{t("Switching to form view will delete any invalid YAML.")}</p>
212	            <Button variant="danger" onClick={onClickYAMLWarningConfirm}>
213	              {t("Switch and delete")}
214	            </Button>
215	            &nbsp;
216	            <Button variant="secondary" onClick={onClickYAMLWarningCancel}>
217	              {t("Cancel")}
218	            </Button>
219	          </Alert>
220	        </FlexItem>
221	      )}
222	
223	      {disabledFormAlert && (
224	        <FlexItem>
225	          <Alert
226	            variant="info"
227	            title={t(
228	              "Form view is disabled for this chart because the schema is not available"
229	            )}
230	            actionClose={
231	              <AlertActionCloseButton
232	                onClose={() => setDisabledFormAlert(false)}
233	              />
234	            }
235	            isInline
236	          />
237	        </FlexItem>
238	      )}
239	
240	      <FlexItem grow={{ default: "grow" }}>
241	        {editorType === EditorType.Form && !disabledFormAlert
242	          ? formContext.editor
243	          : yamlContext.editor}
244	      </FlexItem>
245	    </Flex>
246	  ) : (
247	    <LoadingBox />
248	  );
249	};
250	
251	export default SyncedEditorField;

